<?php  

function send_smtp_mail($to_mail, $to_name, $from_name, $subject, $body, $body_alt, $is_html){
    if($is_html){
        $array_data = [
            //'from' => $from_name . " <no-reply@sandboxfdfa4405c8b94fabb8153f9410d7baaf.mailgun.org>",
            'from' => $from_name . " <no-reply@ipcore.com>",
            'to' => $to_name . " <" . $to_mail . ">",
            'subject' => $subject,
            'html' => $body,
            'text' => $body_alt,
            'o:tracking' => 'yes',
            'o:tracking-clicks' => 'yes',
            'o:tracking-opens' => 'yes'
        ];
        /*$array_data = [
            'from' => 'YOURNAME <YOUR@EMAIL.com>',
            'to' => 'RECIPIENT_NAME <RECIPIENT@EMAIL.COM>',
            'subject' => 'SUBJECT',
            'html' => 'HTML MESSAGE',
            'text' => 'PLAIN_MESSAGE',
            'o:tracking' => 'yes',
            'o:tracking-clicks' => 'yes',
            'o:tracking-opens' => 'yes'
        ];*/
    }
    else{
        $array_data = [
            //'from' => $from_name . " <no-reply@sandboxfdfa4405c8b94fabb8153f9410d7baaf.mailgun.org>",
            'from' => $from_name . " <no-reply@ipcore.com>",
            'to' => $to_name . " <" . $to_mail . ">",
            'subject' => $subject,
            'text' => $body_alt,
            'o:tracking' => 'yes',
            'o:tracking-clicks' => 'yes',
            'o:tracking-opens' => 'yes'
        ];
    }
    $session = curl_init('https://api.eu.mailgun.net/v3/mg.ipcore.com/messages');
    //$session = curl_init('https://api.mailgun.net/v3/sandboxfdfa4405c8b94fabb8153f9410d7baaf.mailgun.org/messages');
    curl_setopt($session, CURLOPT_HTTPAUTH, CURLAUTH_BASIC);
    curl_setopt($session, CURLOPT_USERPWD, MAILGUN_API_KEY);
    curl_setopt($session, CURLOPT_POST, true);
    curl_setopt($session, CURLOPT_POSTFIELDS, $array_data);
    curl_setopt($session, CURLOPT_HEADER, false);
    curl_setopt($session, CURLOPT_ENCODING, 'UTF-8');
    curl_setopt($session, CURLOPT_RETURNTRANSFER, true);
    curl_setopt($session, CURLOPT_SSL_VERIFYPEER, false);
    $response = curl_exec($session);
    curl_close($session);
    
    if ('' != $response) {
        return json_decode($response, true);
    } else {
        return false;
    }
}

