    $subject = "New contact arrived from website's contact form";
    $body = "Full Name: " . $full_name . "\n" .
            "Company/Org. name: " . $org_name . "\n" .
            "Email: " . $email .  "\n" .
            "phonenumber: " . $phone_number . "\n" .
            "Message: " . $tell_us;

    $body_alt = $body;

    send_smtp_mail($to_mail, $to_name, $from_name, $subject, $body, $body_alt, false);
}
